import math


class EigenSolver:
    """Compute eigenvalues and eigenvectors of a 2x2 matrix from scratch."""

    def __init__(self, matrix):
        if len(matrix) != 2 or len(matrix[0]) != 2 or len(matrix[1]) != 2:
            raise ValueError("matrix must be 2x2")
        self.matrix = [
            [float(matrix[0][0]), float(matrix[0][1])],
            [float(matrix[1][0]), float(matrix[1][1])],
        ]

    def eigenvalues(self):
        (a, b), (c, d) = self.matrix
        trace = a + d
        det = a * d - b * c
        disc = trace * trace - 4.0 * det
        if disc < 0:
            real = trace / 2.0
            imag = (-disc) ** 0.5 / 2.0
            return (complex(real, imag), complex(real, -imag))
        s = disc ** 0.5
        return ((trace + s) / 2.0, (trace - s) / 2.0)

    def eigenvector(self, eigenvalue):
        (a, b), (c, d) = self.matrix
        if abs(b) > 1e-10:
            v = [b, eigenvalue - a]
        elif abs(c) > 1e-10:
            v = [eigenvalue - d, c]
        else:
            v = [1.0, 0.0] if abs(a - eigenvalue) < 1e-10 else [0.0, 1.0]
        mag = (v[0] ** 2 + v[1] ** 2) ** 0.5
        return [v[0] / mag, v[1] / mag]

    def apply(self, vector):
        (a, b), (c, d) = self.matrix
        return [a * vector[0] + b * vector[1], c * vector[0] + d * vector[1]]
